#!/usr/bin/env bash
set -euo pipefail

cd /workspace/posthog

TARGET="products/llm_analytics/skills/skills-store/SKILL.md"

# Idempotency: bail out if the gold patch is already applied.
if grep -q 'posthog:skill-file-create' "$TARGET" 2>/dev/null; then
    echo "Patch already applied."
    exit 0
fi

# The gold diff is base64-encoded below to preserve exact whitespace
# (unified-diff context lines for blank rows are space+newline, which
# trailing-whitespace-stripping editors would mangle).
PATCH_B64=""

echo "$PATCH_B64" | base64 -d > /tmp/gold.patch
git apply --whitespace=nowarn /tmp/gold.patch
echo "Patch applied."
